```javascript
var TWO_PI = 6.283;
var GOLDEN_RATIO = 1.618;
var INV_SQRT2 = 0.707;

var physicsConfig = {
  attraction: 4000,
  springCoefficient: 0.004,
  velocityDamping: 0.92,
  gravityTowardCenter: 0.0003,
  maxParticles: 40,
  particleDecayRate: 0.04,
  cameraSmoothing: 0.06
};

var nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

var springs = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',  rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var currentCamera = { x: 400, y: 300, zoom: 1 };
var targetCamera  = { x: 400, y: 300, zoom: 1 };
var particles = [];
var tickCount = 0;

function findNodeById(nodeId) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Coulomb-like repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var repulsionForce = physicsConfig.attraction / (dist * dist);
      var forceX = (dx / dist) * repulsionForce;
      var forceY = (dy / dist) * repulsionForce;
      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Hooke's law spring attraction along edges
  for (var s = 0; s < springs.length; s++) {
    var nodeA = findNodeById(springs[s].a);
    var nodeB = findNodeById(springs[s].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - springs[s].rest;
    var springForce = (springs[s].k || physicsConfig.springCoefficient) * displacement;
    nodeA.vx += (dx / dist) * springForce;
    nodeA.vy += (dy / dist) * springForce;
    nodeB.vx -= (dx / dist) * springForce;
    nodeB.vy -= (dy / dist) * springForce;
  }

  // Integrate velocity, apply damping and center gravity
  for (var n = 0; n < nodes.length; n++) {
    // Gravity toward center (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * physicsConfig.gravityTowardCenter;
    nodes[n].vy += (300 - nodes[n].y) * physicsConfig.gravityTowardCenter;
    // Damping
    nodes[n].vx *= physicsConfig.velocityDamping;
    nodes[n].vy *= physicsConfig.velocityDamping;
    // Position integration
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

function spawnParticle() {
  if (particles.length >= physicsConfig.maxParticles) return;
  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TWO_PI;
  var speed = 0.3 + Math.random() * INV_SQRT2;
  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * INV_SQRT2
  });
}

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.age++;
    // Apply drag based on decay rate
    var dragFactor = 1 - physicsConfig.particleDecayRate * 0.125;
    p.vx *= dragFactor;
    p.vy *= dragFactor;
    p.x += p.vx;
    p.y += p.vy;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

function updateCamera() {
  currentCamera.x += (targetCamera.x - currentCamera.x) * physicsConfig.cameraSmoothing;
  currentCamera.y += (targetCamera.y - currentCamera.y) * physicsConfig.cameraSmoothing;
  currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * physicsConfig.cameraSmoothing;
}

function simulationTick() {
  applyForces();
  updateParticles();
  updateCamera();
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(simulationTick, 16);
```

This is a **force-directed graph layout simulation** with Coulomb repulsion between all nodes, Hooke's law springs along edges, center gravity, velocity damping, a smoothly interpolating camera, and decorative particles emitted from random nodes.
